import { type ReactNode, forwardRef } from 'react'
import { cva, type VariantProps } from 'class-variance-authority'
import { cn } from './cn'

const alertVariants = cva('border rounded-lg p-4', {
  variants: {
    variant: {
      info: 'bg-blue-50 border-blue-200',
      success: 'bg-green-50 border-green-200',
      warning: 'bg-amber-50 border-amber-200',
      error: 'bg-red-50 border-red-200',
    },
  },
  defaultVariants: {
    variant: 'info',
  },
})

const alertIconVariants = cva('', {
  variants: {
    variant: {
      info: 'text-blue-500',
      success: 'text-green-500',
      warning: 'text-amber-500',
      error: 'text-red-500',
    },
  },
})

const alertTitleVariants = cva('text-sm font-medium', {
  variants: {
    variant: {
      info: 'text-blue-800',
      success: 'text-green-800',
      warning: 'text-amber-800',
      error: 'text-red-800',
    },
  },
})

const alertTextVariants = cva('text-sm', {
  variants: {
    variant: {
      info: 'text-blue-700',
      success: 'text-green-700',
      warning: 'text-amber-700',
      error: 'text-red-700',
    },
  },
})

const alertDismissVariants = cva(
  'ml-3 -mr-1.5 -mt-1.5 shrink-0 rounded-lg p-1.5 inline-flex focus:outline-none focus:ring-2 focus:ring-offset-2 transition-colors',
  {
    variants: {
      variant: {
        info: 'text-blue-500 hover:bg-blue-100',
        success: 'text-green-500 hover:bg-green-100',
        warning: 'text-amber-500 hover:bg-amber-100',
        error: 'text-red-500 hover:bg-red-100',
      },
    },
  }
)

const defaultIcons: Record<string, ReactNode> = {
  info: (
    <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
      <path
        fillRule="evenodd"
        d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z"
        clipRule="evenodd"
      />
    </svg>
  ),
  success: (
    <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
      <path
        fillRule="evenodd"
        d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z"
        clipRule="evenodd"
      />
    </svg>
  ),
  warning: (
    <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
      <path
        fillRule="evenodd"
        d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z"
        clipRule="evenodd"
      />
    </svg>
  ),
  error: (
    <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
      <path
        fillRule="evenodd"
        d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z"
        clipRule="evenodd"
      />
    </svg>
  ),
}

export interface AlertProps extends VariantProps<typeof alertVariants> {
  title?: string
  children: ReactNode
  dismissible?: boolean
  onDismiss?: () => void
  icon?: ReactNode
  className?: string
}

export const Alert = forwardRef<HTMLDivElement, AlertProps>(function Alert(
  { variant = 'info', title, children, dismissible = false, onDismiss, icon, className },
  ref
) {
  return (
    <div
      ref={ref}
      role="alert"
      className={cn(alertVariants({ variant }), className)}
    >
      <div className="flex">
        <div className={cn('shrink-0', alertIconVariants({ variant }))}>
          {icon || defaultIcons[variant!]}
        </div>

        <div className="ml-3 flex-1">
          {title && <h3 className={alertTitleVariants({ variant })}>{title}</h3>}
          <div className={cn(alertTextVariants({ variant }), title && 'mt-1')}>
            {children}
          </div>
        </div>

        {dismissible && onDismiss && (
          <button
            type="button"
            onClick={onDismiss}
            className={alertDismissVariants({ variant })}
            aria-label="Fermer"
          >
            <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
              <path
                fillRule="evenodd"
                d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z"
                clipRule="evenodd"
              />
            </svg>
          </button>
        )}
      </div>
    </div>
  )
})

export { alertVariants }
